  <div class="tt-row"><b>Size:</b>    <span id="kgh2-tt-size"></span></div>
  <div class="tt-row"><b>Location:</b><span id="kgh2-tt-loc"></span></div>
</div>

<script>
/* ── Filterable table ── */
function kgh2FilterTable() {
  var countyVal  = document.getElementById('kgh2-county-filter').value;
  var statusVal  = document.getElementById('kgh2-status-filter').value;
  var rows       = document.querySelectorAll('#kgh2-reg-table tbody tr');
  var visible    = 0;

  rows.forEach(function(row) {
    var countyOk = !countyVal || row.dataset.county === countyVal;
    var statusOk = !statusVal || row.dataset.status  === statusVal;
    if (countyOk && statusOk) {
      row.removeAttribute('data-hidden');
      visible++;
    } else {
      row.setAttribute('data-hidden', '1');
    }
  });

  document.getElementById('kgh2-no-results').style.display = visible === 0 ? 'block' : 'none';
}

function kgh2ResetFilters() {
  document.getElementById('kgh2-county-filter').value = '';
  document.getElementById('kgh2-status-filter').value = '';
  kgh2FilterTable();
}

/* ── Collapsible panels ── */
document.addEventListener('DOMContentLoaded', function() {
  document.querySelectorAll('.kgh2-wrap .kgh2-panel .panel-title').forEach(function(title) {
    title.addEventListener('click', function() {
      title.closest('.kgh2-panel').classList.toggle('collapsed');
    });
  });

  /* ── Tooltip ── */
  var tt = document.getElementById('kgh2-tt');
  if (tt) {
    document.querySelectorAll('.kgh2-wrap .marker').forEach(function(m) {
      m.addEventListener('mouseenter', function() {
        document.getElementById('kgh2-tt-name').textContent = m.dataset.n    || '';
        document.getElementById('kgh2-tt-prod').textContent = m.dataset.product || '';
        document.getElementById('kgh2-tt-stat').textContent = m.dataset.status  || '';
        document.getElementById('kgh2-tt-size').textContent = m.dataset.size    || '';
        document.getElementById('kgh2-tt-loc').textContent  = m.dataset.loc     || '';
        tt.classList.add('on');
      });
      m.addEventListener('mousemove', function(e) {
        tt.style.left = (e.clientX + 16) + 'px';
        tt.style.top  = (e.clientY - 16) + 'px';
      });
      m.addEventListener('mouseleave', function() { tt.classList.remove('on'); });
    });
  }
});
</script>
